import{_ as t,r as i,o as s,c as p,a,b as e,d as r,w as c,e as h}from"./app-4c668054.js";const _={},o=h('<h1 id="_2023" tabindex="-1"><a class="header-anchor" href="#_2023" aria-hidden="true">#</a> 2023</h1><h2 id="_20231024" tabindex="-1"><a class="header-anchor" href="#_20231024" aria-hidden="true">#</a> 20231024</h2><p>人类从模仿中起步……所以说人的社会性是必要的。</p><h2 id="_20231018" tabindex="-1"><a class="header-anchor" href="#_20231018" aria-hidden="true">#</a> 20231018</h2><p>少女祈祷中…血液冷却中…体征消失中…</p><h2 id="_20231014" tabindex="-1"><a class="header-anchor" href="#_20231014" aria-hidden="true">#</a> 20231014</h2><p>视聚力和精神力一样，是可再生消耗品</p><h2 id="_20231013" tabindex="-1"><a class="header-anchor" href="#_20231013" aria-hidden="true">#</a> 20231013</h2><p>穿着漏底拖鞋，奔波在阴暗朦胧的下雨天。七天工作日，日日爆课；八股文作业，焦头烂额。</p><hr><p>脑洞：可否使用 IS/PR ratio (issue / pull request) 来衡量开源项目的活跃程度？</p><h2 id="_20231006" tabindex="-1"><a class="header-anchor" href="#_20231006" aria-hidden="true">#</a> 20231006</h2><p>暴论：图片的默认背景应该是透明的。</p><h2 id="_20230928" tabindex="-1"><a class="header-anchor" href="#_20230928" aria-hidden="true">#</a> 20230928</h2>',14),l=a("code",null,".{2}",-1),u=h('<h2 id="_20230927" tabindex="-1"><a class="header-anchor" href="#_20230927" aria-hidden="true">#</a> 20230927</h2><p>不给读权限是很坏的。</p><h2 id="_20230919" tabindex="-1"><a class="header-anchor" href="#_20230919" aria-hidden="true">#</a> 20230919</h2><p>将谐波分析用于气候变化。</p><h2 id="_20230918" tabindex="-1"><a class="header-anchor" href="#_20230918" aria-hidden="true">#</a> 20230918</h2>',5),x={href:"https://www.zhihu.com/question/615395614/answer/3209628247",target:"_blank",rel:"noopener noreferrer"},f=h('<p>很真实，一语点醒</p><h2 id="_20230915" tabindex="-1"><a class="header-anchor" href="#_20230915" aria-hidden="true">#</a> 20230915</h2><p>蝉鸣以群计，乱音均摊风险者也。</p><h2 id="_20230911" tabindex="-1"><a class="header-anchor" href="#_20230911" aria-hidden="true">#</a> 20230911</h2><p>八股 == バグ</p><h2 id="_20230908" tabindex="-1"><a class="header-anchor" href="#_20230908" aria-hidden="true">#</a> 20230908</h2><p>如果我在电子厂里压抑着灵魂，大致的下场是幻想走神然后手指被切掉一截吧。</p><h2 id="_20230906" tabindex="-1"><a class="header-anchor" href="#_20230906" aria-hidden="true">#</a> 20230906</h2><p>层次（level）是各类世界吸引人（我）的一大要素。</p><h2 id="_20230828" tabindex="-1"><a class="header-anchor" href="#_20230828" aria-hidden="true">#</a> 20230828</h2><p>一只隐形的蚊子在蚊帐里，太致命了</p><h2 id="_20230826" tabindex="-1"><a class="header-anchor" href="#_20230826" aria-hidden="true">#</a> 20230826</h2><p>拥有对政治和经济的基础判断，投资黄金就不容易亏。</p><hr><p>物种越安逸，智能可能会越高。牺牲了反应速度，增加神经网络的复杂性。</p><h2 id="_20230824" tabindex="-1"><a class="header-anchor" href="#_20230824" aria-hidden="true">#</a> 20230824</h2><p>不带处理器和存储器提问简直太致命了。。以后问就是中立派折中说。</p><h2 id="_20230817" tabindex="-1"><a class="header-anchor" href="#_20230817" aria-hidden="true">#</a> 20230817</h2><p>苍蝇捕捉器：装过生鱼的袋子。</p><h2 id="_20230814" tabindex="-1"><a class="header-anchor" href="#_20230814" aria-hidden="true">#</a> 20230814</h2><p>小地方民好，官不好；大地方相反（有待验证）。</p><h2 id="_20230802" tabindex="-1"><a class="header-anchor" href="#_20230802" aria-hidden="true">#</a> 20230802</h2><p>Don&#39;t be nervous about mistakes.</p><h2 id="_20230801" tabindex="-1"><a class="header-anchor" href="#_20230801" aria-hidden="true">#</a> 20230801</h2><p>Keep curious, keep learning.</p><h2 id="_20230731" tabindex="-1"><a class="header-anchor" href="#_20230731" aria-hidden="true">#</a> 20230731</h2><p>世间一大遗憾：好看的不露脸，露脸的不好看</p><h2 id="_20230730" tabindex="-1"><a class="header-anchor" href="#_20230730" aria-hidden="true">#</a> 20230730</h2><p>灭蟑记（七）[^1]</p><p>今入厨，已然为灭蟑之师。四处拨弄，意欲惊其而以显于动也。环视之，一蟑伏门后，悄取武器，三击而得，而后方知爆蟑之汁可透双层纸也。</p><p>灭蟑有一理，曰：大蟑喜厨，小蟑喜厕。入厕洗漱，见青年二蟑游走拖鞋之间。移鞋，受惊躲于门轨之缝，竟不可得。持械喝赶之，意欲乱其心智，脱出藏身处。未料其转守为攻，登于械上，占尽先机，欲除吾之械。万幸其年方少，行动迟缓，得以离心之力反击之，投于地，杀之。</p><p>洗脚毕，而脚生瘙痒，有虫豸为乱之感，遂佩叆叇以观之，见三蟑伏于脚跟上。此蟑仅一分（合 1/3 厘米）不足，脚跟皮厚，故感知不甚。投于地，杀之。后再度入浴洗脚。</p><h2 id="_20230728" tabindex="-1"><a class="header-anchor" href="#_20230728" aria-hidden="true">#</a> 20230728</h2><p>B 站的严肃科普都喜欢升华主题是吧，流量密码是吧。。</p><h2 id="_20230719" tabindex="-1"><a class="header-anchor" href="#_20230719" aria-hidden="true">#</a> 20230719</h2><p>猫看似爱干净；但它会去舔自己的足底，我不认为这是干净的表现。</p><h2 id="_20230717" tabindex="-1"><a class="header-anchor" href="#_20230717" aria-hidden="true">#</a> 20230717</h2><p>荞麦等颗粒填充物的枕头有一个优点，那就是能随意调整高度。</p><h2 id="_20230716" tabindex="-1"><a class="header-anchor" href="#_20230716" aria-hidden="true">#</a> 20230716</h2><p>福建人在当今大陆，是比较容易被洗脑的一批人。</p><hr><p>svg 使用了召唤术！召唤出了一只线条恐龙！恐龙单调空虚消失了！</p><p>png 使用了召唤术！召唤出了一只像素恐龙！恐龙变大模糊消失了！</p><hr><p>夏季不要在喜糖里放巧克力，应当是婚宴服务者的基本常识。</p><h2 id="_20230715" tabindex="-1"><a class="header-anchor" href="#_20230715" aria-hidden="true">#</a> 20230715</h2><p>灭蟑记（六）[^1]</p><p>方点灯入厨，一蟑逃窜，另一蟑振翅疾驰而来。本能避之，而先入厨以脚跺逃窜者，其仍余力，钻入柜下。乃反，持拖鞋若泰山，寻方才飞出之蟑，毙其墙上。二蟑前受一压，步履蹒跚，慌不择路，逃离柜底，一击毙命，尸首分离。正欲离去之际，瞥见三蟑静止隐身于盘橱之中。盘橱者，地势低而杂物众，吾见三蟑呆呆傻傻，即清理两蟑尸体，而后清理杂物，终是毙其于绝路。今有<a href="#_20220724">前车之鉴</a>，不敢投于下水道，遂覆纸，碾其头部，葬与桶中，料定死透。</p><h2 id="_20230713" tabindex="-1"><a class="header-anchor" href="#_20230713" aria-hidden="true">#</a> 20230713</h2><p>阅读圈资源比番剧/gal 圈难找多了，鉴定为二次元浓度与技术水平正相关 x</p><h2 id="_20230710" tabindex="-1"><a class="header-anchor" href="#_20230710" aria-hidden="true">#</a> 20230710</h2><p>时穿剧情就像操作裸指针。</p><hr><p>近视眼中的世界，是发散的概率云</p><h2 id="_20230709" tabindex="-1"><a class="header-anchor" href="#_20230709" aria-hidden="true">#</a> 20230709</h2><p>超现实的核心是对世界本质的探寻。</p><h2 id="_20230707" tabindex="-1"><a class="header-anchor" href="#_20230707" aria-hidden="true">#</a> 20230707</h2><p>如果你不喜欢某句话被永久存储、转发，那就不要说</p>',58),b={style:{"text-align":"right"}},g={href:"https://t.me/archlinuxcn_group/2754411",target:"_blank",rel:"noopener noreferrer"},m=h('<h2 id="_20230706" tabindex="-1"><a class="header-anchor" href="#_20230706" aria-hidden="true">#</a> 20230706</h2><p>图论中好像蕴藏者一些大道理. ..</p><hr><p>谨记，勿大声喧哗</p><h2 id="_20230703" tabindex="-1"><a class="header-anchor" href="#_20230703" aria-hidden="true">#</a> 20230703</h2><p>戒胶戒皂，那还打什么呢？</p><h2 id="_20230702" tabindex="-1"><a class="header-anchor" href="#_20230702" aria-hidden="true">#</a> 20230702</h2><p>性恶论与进化论挡在了共产主义面前；.*</p><h2 id="_20230623" tabindex="-1"><a class="header-anchor" href="#_20230623" aria-hidden="true">#</a> 20230623</h2><p>自由研究がいいことだと思う。</p><h2 id="_20230613" tabindex="-1"><a class="header-anchor" href="#_20230613" aria-hidden="true">#</a> 20230613</h2><p>网课和 ChatGPT 是相辅相成的：前者负责教学，后者负责答疑。我很期待能淘汰老师和线下教学的那一天。</p><h2 id="_20230609" tabindex="-1"><a class="header-anchor" href="#_20230609" aria-hidden="true">#</a> 20230609</h2><p>原以为我被世事打磨圆滑，然而骗不了自己不可久藏那一点锋芒。</p><hr><p>大学是猫的黑域。</p><hr><p>不要迷失在欲望之中，独行是我灵感的泉源。</p><hr><p>想经由网跨越阶级，则必先打破网之枷锁。</p><hr><p>以长远眼光放大自我，谓之成长。</p><hr><p>踏尘土而染之，方知其必有可恨之处也。</p><h2 id="_20230608" tabindex="-1"><a class="header-anchor" href="#_20230608" aria-hidden="true">#</a> 20230608</h2><p>站在牲畜的角度，并没有为主人牺牲的必要。</p><h2 id="_20230606" tabindex="-1"><a class="header-anchor" href="#_20230606" aria-hidden="true">#</a> 20230606</h2><p>我的手机体会到了我的杀意。我尝试解 bl 锁，结果手机流量断网了，重启也打不开；我等着，结果手机表面出现了类似凝固的血滴的暗红色圆形固体物质。</p><h2 id="_20230605" tabindex="-1"><a class="header-anchor" href="#_20230605" aria-hidden="true">#</a> 20230605</h2><p>反向看本，界原展开</p><h2 id="_20230531" tabindex="-1"><a class="header-anchor" href="#_20230531" aria-hidden="true">#</a> 20230531</h2><p>你的手鸡快冲是几毫升的？</p><h2 id="_20230529" tabindex="-1"><a class="header-anchor" href="#_20230529" aria-hidden="true">#</a> 20230529</h2><p>枯れない世界と終わる花 -&gt; sendan life -?&gt; 先端（せんたん）ライフ -?&gt; 前端工程师（フロントエンド・エンジニア）的生活 <s>（误</s></p><hr><p>空调是正反馈：当少量人开始开空调，排放的热气使环境极速升温，大家都开始开空调，室外温度达到饱和</p><h2 id="_20230528" tabindex="-1"><a class="header-anchor" href="#_20230528" aria-hidden="true">#</a> 20230528</h2><p>笑是正反馈：不明白为什么笑，但就是被传染着笑，最后笑声达到饱和后衰减</p><h2 id="_20230524" tabindex="-1"><a class="header-anchor" href="#_20230524" aria-hidden="true">#</a> 20230524</h2><p>我现在所做之事，是否违背了我对死亡的主张？</p><h2 id="_20230516" tabindex="-1"><a class="header-anchor" href="#_20230516" aria-hidden="true">#</a> 20230516</h2><p>不要弄混了爱欲，色欲和性欲啊！</p><hr><p>宿舍桌子是充能器，累了的时候趴一下就能充能。</p><h2 id="_20230411" tabindex="-1"><a class="header-anchor" href="#_20230411" aria-hidden="true">#</a> 20230411</h2><p>传签到表是一种混乱的行为：若无外力规定传递次序，每个人以随机方向朝四周传递（实际上真的挺随机），几乎不可能遍历到所有的点。已经签过到的人视其为烫手山芋，推诿拒绝；拒力不足的，无奈接过山芋，开始寻找其他方向的破绽。而当你环视四周，皆闭目谢表，于是将其上传给老师，无形中也承担了可能还有人没签到，进而被老师怒斥的风险。</p><p>问：谁之过也？</p><h2 id="_2023-03-xx" tabindex="-1"><a class="header-anchor" href="#_2023-03-xx" aria-hidden="true">#</a> 2023.03.xx</h2><p>寄生虫也是积分器</p><h2 id="_20230326" tabindex="-1"><a class="header-anchor" href="#_20230326" aria-hidden="true">#</a> 20230326</h2><p>体验有两种：亲身经历与脑内模拟。二者不可兼得，该如何选择？</p><h2 id="_20230325" tabindex="-1"><a class="header-anchor" href="#_20230325" aria-hidden="true">#</a> 20230325</h2><p>一年前的此时，我面对着封城封校的静寂处境，在纸上魔法使的宝石之中，聆听着各色书册物语。</p><h2 id="_20230324" tabindex="-1"><a class="header-anchor" href="#_20230324" aria-hidden="true">#</a> 20230324</h2><p>思维打开，<span class="heimu" title="你知道的太多了">屎又何尝不是一种肛塞呢？</span></p><h2 id="_20230322" tabindex="-1"><a class="header-anchor" href="#_20230322" aria-hidden="true">#</a> 20230322</h2><p>自私是生命的公理。</p><hr><p>商业化拥有许多令人不快的机制，但也为普罗众生提供了便利。</p><h2 id="_20230318" tabindex="-1"><a class="header-anchor" href="#_20230318" aria-hidden="true">#</a> 20230318</h2><p>一个正反馈系统的例子：快下课，骚动 -&gt; 听不进课，老师选择提前下课 -&gt; 造成更大的骚动</p><h2 id="_20230313" tabindex="-1"><a class="header-anchor" href="#_20230313" aria-hidden="true">#</a> 20230313</h2><p>It&#39;s difficult to balance <strong>learning</strong> and <strong>exploring</strong>.</p><h2 id="_20230307" tabindex="-1"><a class="header-anchor" href="#_20230307" aria-hidden="true">#</a> 20230307</h2><p>死亡是生物最大的不自由。</p><h2 id="_20230222" tabindex="-1"><a class="header-anchor" href="#_20230222" aria-hidden="true">#</a> 20230222</h2><ul><li>当今，由于武器技术发展，中低层人民的反抗能力无限减弱，某些原理不再适用。</li><li>（哲学意义上的）自由会产生灵感的激烈碰撞以推动社会进步。不自由的社会没有未来。</li><li>技术改变世界。对未来社会的预想需要与对未来技术的预想结合。</li></ul><h2 id="_20230221" tabindex="-1"><a class="header-anchor" href="#_20230221" aria-hidden="true">#</a> 20230221</h2><p>发现命运经常让我获得挺不错但算不上完美的结果。</p><h2 id="_20230217" tabindex="-1"><a class="header-anchor" href="#_20230217" aria-hidden="true">#</a> 20230217</h2><p>更认可<em>道由心生</em>。</p><hr><p>身体完全掌控，为一道。非大毅力持之以恒者，弗可进。此为武夫之道，若遭绝望，如何？</p><h2 id="_20230216" tabindex="-1"><a class="header-anchor" href="#_20230216" aria-hidden="true">#</a> 20230216</h2><p>“不拘一物，不羁一念，方是自由。”<div style="text-align:right;font-style:italic;">——《知北游》</div> 我言：矛盾平衡处生自由。一念则静，一念则动，自由在其中矣。</p><hr><p>今有一疑：道在天地？道在我心？</p><h2 id="_20230210" tabindex="-1"><a class="header-anchor" href="#_20230210" aria-hidden="true">#</a> 20230210</h2><p>家里蹲虽爽， 却会失去一些幻想，灵感与思考。</p><h2 id="_20230131" tabindex="-1"><a class="header-anchor" href="#_20230131" aria-hidden="true">#</a> 20230131</h2><p>赖床看小说可以养生：挤占了本来会拿来看 H 的时间。</p><h2 id="_20230130" tabindex="-1"><a class="header-anchor" href="#_20230130" aria-hidden="true">#</a> 20230130</h2><p>重要的东西总是在不经意间建立起来的。我过去的 12 年学习生涯是失败的，而现在我需要去接受这些失败。</p><h2 id="_20230126" tabindex="-1"><a class="header-anchor" href="#_20230126" aria-hidden="true">#</a> 20230126</h2><p>华莱士是穷人是聚集地。然而当我常看到一些高龄人在华莱士一边点着血亏单品 / 套餐一边心疼钱包的时候，还是挺感慨的。</p><h2 id="_20230113" tabindex="-1"><a class="header-anchor" href="#_20230113" aria-hidden="true">#</a> 20230113</h2><p>深入分析演练固然是好事，但也失去了那破釜沉舟的勇气。</p><h2 id="_20230109" tabindex="-1"><a class="header-anchor" href="#_20230109" aria-hidden="true">#</a> 20230109</h2><p>凡书中英雄，多正义，多为苍生，多敢作敢当。他日吾若著书，必逆此律。</p>',89);function k(v,w){const n=i("RouterLink"),d=i("ExternalLinkIcon");return s(),p("div",null,[o,a("p",null,[e("尝试对我在路上看到的尽可能多的 "),l,e(" 进行"),r(n,{to:"/hobbies/NSFW/videos.html"},{default:c(()=>[e("videos")]),_:1}),e("的颜打分。")]),u,a("blockquote",null,[a("p",null,[e("IT 行业本质上是一个服务型行业——"),a("a",x,[e("src"),r(d)])])]),f,a("div",b,[a("p",null,[a("em",null,[e("——oldherl, "),a("a",g,[e("archlinux-cn"),r(d)])])])]),m])}const N=t(_,[["render",k],["__file","2023.html.vue"]]);export{N as default};
